@namespace sv_fcd72c447cab4c47ad627df36670e756.Components.Apply
@using sv_fcd72c447cab4c47ad627df36670e756.Models

<h4 class="mb-3">Personal Information</h4>

@if (Error is not null)
{
    <div class="alert alert-danger">@Error</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Model.FullName"
               @onchange="e => Model = Model with { FullName = (string?)e.Value ?? "" }" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(EmailError is not null ? "is-invalid" : "")"
               value="@Model.Email"
               @onchange="e => Model = Model with { Email = (string?)e.Value ?? "" }" />
        @if (EmailError is not null)
        {
            <div class="invalid-feedback">@EmailError</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" value="@Model.Phone"
               @onchange="e => Model = Model with { Phone = (string?)e.Value ?? "" }" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Model.Address"
               @onchange="e => Model = Model with { Address = (string?)e.Value ?? "" }" />
    </div>
</div>

<div class="mt-4 d-flex justify-content-end">
    <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Model { get; set; } = default!;
    [Parameter] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService AppService { get; set; } = default!;

    private string? Error;
    private string? EmailError;
    private bool IsValidating;

    private async Task HandleNext()
    {
        Error = null;
        EmailError = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            Error = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var valid = await AppService.ValidateEmailAsync(Model.Email);
            if (!valid)
            {
                EmailError = "Please enter a valid email address.";
                return;
            }
            await OnNext.InvokeAsync(Model);
        }
        finally
        {
            IsValidating = false;
        }
    }
}

@namespace sv_fcd72c447cab4c47ad627df36670e756.Components.Apply
@using sv_fcd72c447cab4c47ad627df36670e756.Models

<h4 class="mb-3">Work History</h4>

@if (Error is not null)
{
    <div class="alert alert-danger">@Error</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]"
                   Index="index + 1"
                   ShowRemove="Entries.Count > 1"
                   OnChanged="e => UpdateEntry(index, e)"
