@namespace sv_fcd72c447cab4c47ad627df36670e756.Components.Apply

<nav class="mb-4">
    <div class="d-flex justify-content-between position-relative">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var step = i;
            var isCurrent = step == CurrentStep;
            var isCompleted = step < CurrentStep;
            var isFuture = step > CurrentStep;

            <div class="text-center flex-fill" style="z-index: 1;">
                <button type="button"
                        class="btn rounded-circle d-inline-flex align-items-center justify-content-center @StepBadgeClass(step)"
                        style="width: 40px; height: 40px; font-size: 0.85rem;"
                        disabled="@isFuture"
                        @onclick="() => OnStepClicked.InvokeAsync(step)">
                    @if (isCompleted)
                    {
                        <span>&#10003;</span>
                    }
                    else
                    {
                        <span>@(step + 1)</span>
                    }
                </button>
                <div class="small mt-1 @(isFuture ? "text-muted" : isCurrent ? "fw-bold" : "")">
                    @StepNames[step]
                </div>
            </div>
        }
    </div>
</nav>

@code {
    private static readonly string[] StepNames =
        ["Personal Info", "Work History", "References", "Cover Letter", "Review & Submit"];

    [Parameter, EditorRequired] public int CurrentStep { get; set; }
    [Parameter] public EventCallback<int> OnStepClicked { get; set; }

    private string StepBadgeClass(int step) => step switch
    {
        _ when step == CurrentStep => "btn-primary",
        _ when step < CurrentStep => "btn-success",
        _ => "btn-outline-secondary"
    };
}

