@namespace sv_fcd72c447cab4c47ad627df36670e756.Components.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Position @Index</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-sm btn-outline-danger" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Company Name</label>
                <input type="text" class="form-control" value="@Entry.Company"
                       @onchange="e => Update(Entry with { Company = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Job Title</label>
                <input type="text" class="form-control" value="@Entry.Title"
                       @onchange="e => Update(Entry with { Title = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">Start Date</label>
                <input type="date" class="form-control" value="@Entry.StartDate.ToString("yyyy-MM-dd")"
                       @onchange="e => Update(Entry with { StartDate = DateTime.Parse((string?)e.Value ?? DateTime.Today.ToString("yyyy-MM-dd")) })" />
            </div>
            <div class="col-md-4">
                <label class="form-label">End Date</label>
                <input type="date" class="form-control" value="@(Entry.EndDate?.ToString("yyyy-MM-dd") ?? "")"
                       disabled="@IsCurrent"
                       @onchange="e => Update(Entry with { EndDate = DateTime.TryParse((string?)e.Value, out var d) ? d : null })" />
            </div>
            <div class="col-md-4 d-flex align-items-end">
                <div class="form-check mb-2">
                    <input type="checkbox" class="form-check-input" id="@($"current-{Index}")" checked="@IsCurrent"
                           @onchange="ToggleCurrent" />
                    <label class="form-check-label" for="@($"current-{Index}")">Currently working here</label>
                </div>
            </div>
            <div class="col-12">
                <label class="form-label">Description</label>
                <textarea class="form-control" rows="3" value="@Entry.Description"
                          @onchange="e => Update(Entry with { Description = (string?)e.Value ?? "" })"></textarea>
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public WorkEntry Entry { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback<WorkEntry> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private bool IsCurrent => Entry.EndDate is null;

    private void Update(WorkEntry updated) => OnChanged.InvokeAsync(updated);

    private void ToggleCurrent(ChangeEventArgs e)
    {
        var isCurrentNow = (bool)(e.Value ?? false);
        Update(Entry with { EndDate = isCurrentNow ? null : DateTime.Today });
    }
}

@namespace sv_fcd72c447cab4c47ad627df36670e756.Components.Apply

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @Index</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-sm btn-outline-danger" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name</label>
                <input type="text" class="form-control" value="@Reference.Name"
                       @onchange="e => Update(Reference with { Name = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship</label>
                <input type="text" class="form-control" value="@Reference.Relationship"
                       @onchange="e => Update(Reference with { Relationship = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" value="@Reference.Email"
                       @onchange="e => Update(Reference with { Email = (string?)e.Value ?? "" })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone</label>
                <input type="tel" class="form-control" value="@Reference.Phone"
                       @onchange="e => Update(Reference with { Phone = (string?)e.Value ?? "" })" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Reference Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback<Reference> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private void Update(Reference updated) => OnChanged.InvokeAsync(updated);
}

@namespace sv_fcd72c447cab4c47ad627df36670e756.Components.Apply
@using sv_fcd72c447cab4c47ad627df36670e756.Models

<h4 class="mb-3">Personal Information</h4>

@if (Error is not null)
{
    <div class="alert alert-danger">@Error</div>
}

<div class="row g-3">
    <div class="col-md-6">
        <label class="form-label">Full Name <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Model.FullName"
               @onchange="e => Model = Model with { FullName = (string?)e.Value ?? "" }" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Email <span class="text-danger">*</span></label>
        <input type="email" class="form-control @(EmailError is not null ? "is-invalid" : "")"
               value="@Model.Email"
               @onchange="e => Model = Model with { Email = (string?)e.Value ?? "" }" />
        @if (EmailError is not null)
        {
            <div class="invalid-feedback">@EmailError</div>
        }
    </div>
    <div class="col-md-6">
        <label class="form-label">Phone <span class="text-danger">*</span></label>
        <input type="tel" class="form-control" value="@Model.Phone"
               @onchange="e => Model = Model with { Phone = (string?)e.Value ?? "" }" />
    </div>
    <div class="col-md-6">
        <label class="form-label">Address <span class="text-danger">*</span></label>
        <input type="text" class="form-control" value="@Model.Address"
               @onchange="e => Model = Model with { Address = (string?)e.Value ?? "" }" />
    </div>
</div>

<div class="mt-4 d-flex justify-content-end">
    <button type="button" class="btn btn-primary" @onclick="HandleNext" disabled="@IsValidating">
        @if (IsValidating)
        {
            <span class="spinner-border spinner-border-sm me-1"></span>
        }
        Next
    </button>
</div>

@code {
    [Parameter, EditorRequired] public PersonalInfo Model { get; set; } = default!;
    [Parameter] public EventCallback<PersonalInfo> OnNext { get; set; }
    [Parameter, EditorRequired] public IApplicationService AppService { get; set; } = default!;

    private string? Error;
    private string? EmailError;
    private bool IsValidating;

    private async Task HandleNext()
    {
        Error = null;
        EmailError = null;

        if (string.IsNullOrWhiteSpace(Model.FullName) ||
            string.IsNullOrWhiteSpace(Model.Email) ||
            string.IsNullOrWhiteSpace(Model.Phone) ||
            string.IsNullOrWhiteSpace(Model.Address))
        {
            Error = "All fields are required.";
            return;
        }

        IsValidating = true;
        try
        {
            var valid = await AppService.ValidateEmailAsync(Model.Email);
            if (!valid)
            {
                EmailError = "Please enter a valid email address.";
                return;
            }
            await OnNext.InvokeAsync(Model);
        }
        finally
        {
            IsValidating = false;
        }
    }
}

