@namespace sv_fcd72c447cab4c47ad627df36670e756.Components.Apply
@using sv_fcd72c447cab4c47ad627df36670e756.Models

<h4 class="mb-3">Work History</h4>

@if (Error is not null)
{
    <div class="alert alert-danger">@Error</div>
}

@for (int i = 0; i < Entries.Count; i++)
{
    var index = i;
    <WorkEntryForm Entry="Entries[index]"
                   Index="index + 1"
                   ShowRemove="Entries.Count > 1"
                   OnChanged="e => UpdateEntry(index, e)"
                   OnRemove="() => RemoveEntry(index)" />
}

<button type="button" class="btn btn-outline-primary mb-3" @onclick="AddEntry">
    + Add Another Position
</button>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync(Entries)">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<WorkEntry> Entries { get; set; } = default!;
    [Parameter] public EventCallback<List<WorkEntry>> OnNext { get; set; }
    [Parameter] public EventCallback<List<WorkEntry>> OnBack { get; set; }

    private string? Error;

    private void UpdateEntry(int index, WorkEntry updated)
    {
        Entries[index] = updated;
    }

    private void AddEntry()
    {
        Entries.Add(new WorkEntry("", "", DateTime.Today, null, ""));
    }

    private void RemoveEntry(int index)
    {
        Entries.RemoveAt(index);
    }

    private void HandleNext()
    {
        Error = null;
        foreach (var entry in Entries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title))
            {
                Error = "Each position must have a company name and job title.";
                return;
            }
        }
        OnNext.InvokeAsync(Entries);
    }
}

