@namespace sv_fcd72c447cab4c47ad627df36670e756.Components.Apply
@using sv_fcd72c447cab4c47ad627df36670e756.Models

<h4 class="mb-3">References</h4>

@if (Error is not null)
{
    <div class="alert alert-danger">@Error</div>
}

@for (int i = 0; i < References.Count; i++)
{
    var index = i;
    <ReferenceForm Reference="References[index]"
                   Index="index + 1"
                   ShowRemove="References.Count > 1"
                   OnChanged="e => UpdateReference(index, e)"
                   OnRemove="() => RemoveReference(index)" />
}

@if (References.Count < 3)
{
    <button type="button" class="btn btn-outline-primary mb-3" @onclick="AddReference">
        + Add Reference
    </button>
}

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync(References)">Back</button>
    <button type="button" class="btn btn-primary" @onclick="HandleNext">Next</button>
</div>

@code {
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = default!;
    [Parameter] public EventCallback<List<Reference>> OnNext { get; set; }
    [Parameter] public EventCallback<List<Reference>> OnBack { get; set; }

    private string? Error;

    private void UpdateReference(int index, Reference updated)
    {
        References[index] = updated;
    }

    private void AddReference()
    {
        if (References.Count < 3)
            References.Add(new Reference("", "", "", ""));
    }

    private void RemoveReference(int index)
    {
        References.RemoveAt(index);
    }

    private void HandleNext()
    {
        Error = null;
        foreach (var r in References)
        {
            if (string.IsNullOrWhiteSpace(r.Name) || string.IsNullOrWhiteSpace(r.Email))
            {
                Error = "Each reference must have a name and email.";
                return;
            }
        }
        OnNext.InvokeAsync(References);
    }
}

