@namespace sv_fcd72c447cab4c47ad627df36670e756.Components.Apply

<h4 class="mb-3">Cover Letter</h4>

<div class="mb-2">
    <textarea class="form-control" rows="12" value="@CoverLetter"
              @oninput="HandleInput"
              maxlength="@MaxLength"></textarea>
</div>
<div class="text-muted text-end mb-3">
    @CoverLetter.Length / @MaxLength characters
</div>

<div class="d-flex justify-content-between">
    <button type="button" class="btn btn-secondary" @onclick="() => OnBack.InvokeAsync(CoverLetter)">Back</button>
    <button type="button" class="btn btn-primary" @onclick="() => OnNext.InvokeAsync(CoverLetter)">Next</button>
</div>

@code {
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<string> OnNext { get; set; }
    [Parameter] public EventCallback<string> OnBack { get; set; }

    private const int MaxLength = 2000;

    private void HandleInput(ChangeEventArgs e)
    {
        var text = (string?)e.Value ?? "";
        CoverLetter = text.Length > MaxLength ? text[..MaxLength] : text;
    }
}

@namespace sv_fcd72c447cab4c47ad627df36670e756.Components.Apply
@using sv_fcd72c447cab4c47ad627df36670e756.Models

<h4 class="mb-3">Review & Submit</h4>

@if (SubmittedId is not null)
{
    <div class="alert alert-success">
        <h5>Application Submitted!</h5>
        <p class="mb-0">Your application ID is <strong>@SubmittedId</strong>. Please save this for your records.</p>
    </div>
}
else
{
    @if (Error is not null)
    {
        <div class="alert alert-danger">@Error</div>
    }

    <!-- Personal Info -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Personal Information</strong>
            <a href="#" @onclick="() => OnEdit.InvokeAsync(0)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6"><strong>Name:</strong> @Personal.FullName</div>
                <div class="col-md-6"><strong>Email:</strong> @Personal.Email</div>
                <div class="col-md-6"><strong>Phone:</strong> @Personal.Phone</div>
                <div class="col-md-6"><strong>Address:</strong> @Personal.Address</div>
            </div>
        </div>
    </div>

    <!-- Work History -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Work History</strong>
            <a href="#" @onclick="() => OnEdit.InvokeAsync(1)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            @foreach (var entry in WorkEntries)
            {
                <div class="mb-3 pb-3 border-bottom">
                    <div><strong>@entry.Title</strong> at @entry.Company</div>
                    <div class="text-muted">
                        @entry.StartDate.ToString("MMM yyyy") &mdash;
                        @(entry.EndDate?.ToString("MMM yyyy") ?? "Present")
                    </div>
                    @if (!string.IsNullOrWhiteSpace(entry.Description))
                    {
                        <div class="mt-1">@entry.Description</div>
                    }
                </div>
            }
        </div>
    </div>

    <!-- References -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>References</strong>
            <a href="#" @onclick="() => OnEdit.InvokeAsync(2)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            @foreach (var r in References)
            {
                <div class="mb-2">
                    <strong>@r.Name</strong> (@r.Relationship) &mdash; @r.Email, @r.Phone
                </div>
            }
        </div>
    </div>

    <!-- Cover Letter -->
    <div class="card mb-3">
        <div class="card-header d-flex justify-content-between align-items-center">
            <strong>Cover Letter</strong>
            <a href="#" @onclick="() => OnEdit.InvokeAsync(3)" @onclick:preventDefault>Edit</a>
        </div>
        <div class="card-body">
            <p style="white-space: pre-wrap;">@CoverLetter</p>
        </div>
    </div>

    <div class="d-flex justify-content-between">
        <button type="button" class="btn btn-secondary" @onclick="() => OnEdit.InvokeAsync(3)">Back</button>
        <button type="button" class="btn btn-success btn-lg" @onclick="HandleSubmit" disabled="@IsSubmitting">
            @if (IsSubmitting)
            {
                <span class="spinner-border spinner-border-sm me-1"></span>
            }
            Submit Application
        </button>
    </div>
}

@code {
    [Parameter, EditorRequired] public PersonalInfo Personal { get; set; } = default!;
    [Parameter, EditorRequired] public List<WorkEntry> WorkEntries { get; set; } = default!;
    [Parameter, EditorRequired] public List<Reference> References { get; set; } = default!;
    [Parameter] public string CoverLetter { get; set; } = "";
    [Parameter] public EventCallback<int> OnEdit { get; set; }
    [Parameter] public EventCallback OnSubmit { get; set; }

    private bool IsSubmitting;
    private int? SubmittedId;
    private string? Error;

    [Parameter] public int? ApplicationId { get; set; }

    protected override void OnParametersSet()
    {
        if (ApplicationId is not null)
            SubmittedId = ApplicationId;
    }

    private async Task HandleSubmit()
    {
        IsSubmitting = true;
        Error = null;
        try
        {
            await OnSubmit.InvokeAsync();
        }
        catch (Exception ex)
        {
            Error = $"Submission failed: {ex.Message}";
        }
        finally
        {
            IsSubmitting = false;
        }
    }
}

