<PageTitle>Job Application</PageTitle>

<div class="container py-4" style="max-width: 800px;">
    <h2 class="mb-4">Job Application</h2>

    <StepIndicator CurrentStep="currentStep" OnStepClicked="GoToStep" />

    @switch (currentStep)
    {
        case 0:
            <PersonalInfoStep Model="personalInfo"
                              AppService="AppService"
                              OnNext="HandlePersonalNext" />
            break;
        case 1:
            <WorkHistoryStep Entries="workEntries"
                             OnNext="HandleWorkNext"
                             OnBack="HandleWorkBack" />
            break;
        case 2:
            <ReferencesStep References="references"
                            OnNext="HandleReferencesNext"
                            OnBack="HandleReferencesBack" />
            break;
        case 3:
            <CoverLetterStep CoverLetter="coverLetter"
                             OnNext="HandleCoverLetterNext"
                             OnBack="HandleCoverLetterBack" />
            break;
        case 4:
            <ReviewStep Personal="personalInfo"
                        WorkEntries="workEntries"
                        References="references"
                        CoverLetter="coverLetter"
                        ApplicationId="applicationId"
                        OnEdit="GoToStep"
                        OnSubmit="HandleSubmit" />
            break;
    }
</div>

@code {
    private int currentStep;
    private int? applicationId;

    private PersonalInfo personalInfo = new("", "", "", "");
    private List<WorkEntry> workEntries = [new("", "", DateTime.Today, null, "")];
    private List<Reference> references = [new("", "", "", ""), new("", "", "", "")];
    private string coverLetter = "";

    private void GoToStep(int step)
    {
        if (step < currentStep)
            currentStep = step;
    }

    private void HandlePersonalNext(PersonalInfo info)
    {
        personalInfo = info;
        currentStep = 1;
    }

    private void HandleWorkNext(List<WorkEntry> entries)
    {
        workEntries = entries;
        currentStep = 2;
    }

    private void HandleWorkBack(List<WorkEntry> entries)
    {
        workEntries = entries;
        currentStep = 0;
    }

    private void HandleReferencesNext(List<Reference> refs)
    {
        references = refs;
        currentStep = 3;
    }

    private void HandleReferencesBack(List<Reference> refs)
    {
        references = refs;
        currentStep = 1;
    }

    private void HandleCoverLetterNext(string text)
    {
        coverLetter = text;
        currentStep = 4;
    }

    private void HandleCoverLetterBack(string text)
    {
        coverLetter = text;
        currentStep = 2;
    }

    private async Task HandleSubmit()
    {
        var application = new JobApplication(
            personalInfo,
            new WorkHistory(workEntries),
            references,
            coverLetter);

        applicationId = await AppService.SubmitApplicationAsync(application);
        StateHasChanged();
    }
}

