        OnChanged.InvokeAsync(Entry with { Description = Str(e.Value) });

    private void ToggleCurrent(ChangeEventArgs e)
    {
        var isCurrentNow = (bool)(e.Value ?? false);
        OnChanged.InvokeAsync(Entry with { EndDate = isCurrentNow ? null : DateTime.Today });
    }
}

