@using sv_fcd72c447cab4c47ad627df36670e756.Models

<div class="card mb-3">
    <div class="card-body">
        <div class="d-flex justify-content-between align-items-center mb-3">
            <h6 class="card-title mb-0">Reference @Index</h6>
            @if (ShowRemove)
            {
                <button type="button" class="btn btn-sm btn-outline-danger" @onclick="OnRemove">Remove</button>
            }
        </div>

        <div class="row g-3">
            <div class="col-md-6">
                <label class="form-label">Name</label>
                <input type="text" class="form-control" value="@Reference.Name"
                       @onchange="e => Update(Reference with { Name = (string?)e.Value ?? string.Empty })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Relationship</label>
                <input type="text" class="form-control" value="@Reference.Relationship"
                       @onchange="e => Update(Reference with { Relationship = (string?)e.Value ?? string.Empty })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Email</label>
                <input type="email" class="form-control" value="@Reference.Email"
                       @onchange="e => Update(Reference with { Email = (string?)e.Value ?? string.Empty })" />
            </div>
            <div class="col-md-6">
                <label class="form-label">Phone</label>
                <input type="tel" class="form-control" value="@Reference.Phone"
                       @onchange="e => Update(Reference with { Phone = (string?)e.Value ?? string.Empty })" />
            </div>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public Reference Reference { get; set; } = default!;
    [Parameter] public int Index { get; set; }
    [Parameter] public bool ShowRemove { get; set; }
    [Parameter] public EventCallback<Reference> OnChanged { get; set; }
    [Parameter] public EventCallback OnRemove { get; set; }

    private void Update(Reference updated) => OnChanged.InvokeAsync(updated);
}

